  ('disabled-6f0ba476-moex-00311', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於意思表示錯誤撤銷之敘述，下列何者錯誤？', '["當事人資格之錯誤，若交易上認為重要者，視為內容錯誤", "錯誤之表意人必須無過失", "撤銷權自意思表示後，經過1年而消滅", "物之性質錯誤視為動機錯誤，不得撤銷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00312', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於任意認領之敘述，下列何者錯誤？', '["認領權為形成權", "認領為無相對人之單獨行為", "認領為要式行為", "認領為身分行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
