  ('disabled-6f0ba476-moex-00314', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者非屬民法所稱之法人？', '["農會", "合夥", "工會", "無限公司"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00315', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲與乙電器行訂立買賣契約，以新臺幣2萬元向乙購買一台冰箱，雙方約 定乙應於民國111年2月2日下午2時將冰箱送至甲之住所。乙於約定時 間，依債務之本旨將冰箱送至甲之住所，詎料甲竟不在家。下列何者正確？', '["甲應負給付遲延及受領遲延之責任", "甲僅負給付遲延或受領遲延之責任", "甲無須負給付遲延之責任", "甲無須負受領遲延之責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00316', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於民法代理之敘述，下列何者錯誤？', '["代理人得代理本人以現物清償債務", "代理人得代理本人為無主物先占", "代理人得代理本人主張以同種給付之債務進行抵銷", "父母贈與限制行為能力之子女不動產之法律行為有效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00317', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '就民法第180條第3款規定，「因清償債務而為給付，於給付時明知無給 付之義務者」，不得請求返還之適用，下列何者正確？', '["是否於給付時明知無給付之義務，應由受領人舉證證明之", "給付人因重大過失而不知無給付之義務者，亦準用之", "受脅迫而為之給付，亦屬給付時明知無給付之義務，適用本規定", "判斷是否明知無給付之義務時，須綜合考量受領人是否亦有明知之主觀 意思"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00318', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲於乙所有之動產中，發見埋藏物而占有者，其所有權之歸屬如何？', '["由發見人甲取得埋藏物之所有權，乙得依關於不當得利之規定，請求償 還相當之價額", "由動產所有人乙取得埋藏物之所有權，甲得依關於不當得利之規定，請 求償還相當之價額", "由發見人甲與動產所有人乙各取得埋藏物之半", "由發見人甲與動產所有人乙，按其埋藏物與該動產之價值，共有埋藏物 之所有權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00319', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲經營化學工廠，因管線腐蝕，化學氣體外洩，導致附近居民乙受傷，乙 請求甲損害賠償。下列何者正確？', '["乙應證明因甲之過失導致乙受有損害", "乙應證明甲工廠營業有致其受損害之危險", "乙應證明甲係屬不法經營化學工廠", "乙應證明其損害與甲工廠有因果關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00320', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲將所有之 A 屋，出租於乙供營業使用。甲交付 A 屋於乙後，A 屋因天 災導致天花板漏水。關於甲乙間之權利義務關係，下列何者錯誤？', '["因天災導致漏水，係非可歸責於雙方當事人之事由，甲無須負修繕義務", "甲乙得於契約中約定，由乙負擔修繕義務", "甲乙若未於契約為特別約定，依民法第429條有關出租人修繕義務之規 定，係由甲負擔修繕義務", "無論修繕義務由何人負擔，甲為保存租賃物所為之必要行為，乙不得拒絕"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
